/**
 * SQL 安全校验器
 * 优先从数据库白名单表读取，fallback 到配置文件
 */
@Bean
public SqlSecurityValidator sqlSecurityValidator(
        @Value("${nl2sql.security.max-sql-length:500}")
        int maxSqlLength) {

    // 1. 尝试从数据库白名单表读取
    List<Whitelist> whitelist = whitelistMapper.selectList(new QueryWrapper<>());
    List<String> allowedTables;

    if (whitelist != null && !whitelist.isEmpty()) {
        allowedTables = whitelist.stream()
                .map(Whitelist::getTableName)
                .collect(Collectors.toList());
        log.info("[Factory] 使用数据库白名单，共 {} 张表: {}", allowedTables.size(), allowedTables);
    } else {
        // 2. Fallback: 从配置文件读取
        allowedTables = Arrays.asList(configAllowedTables.split(","));
        log.info("[Factory] 数据库白名单为空，使用配置文件默认配置，共 {} 张表: {}", allowedTables.size(), allowedTables);
    }

    return new SqlSecurityValidator(allowedTables, maxSqlLength);
}

